SELECT GROUP_CONCAT(
    evaluation_date || ' - ' || overall_score || ' - ' || evaluation_comments, '\n'
) AS evaluation_summary
FROM evaluations ev
INNER JOIN instructors i ON ev.instructor_id = i.instructor_id
WHERE i.instructor_id = 1 AND ev.evaluation_type = 'Final';

SELECT AVG(overall_score) AS average_overall_score
FROM evaluations
WHERE project_id = 1;

SELECT participation_score
FROM group_members
WHERE member_status = 'Active';
